                    elif any(k in snippet for k in design_kw):
                        status = 'design'
                    elif any(k in snippet for k in not_started_kw):
                        status = 'not started'
                    elif any(k in snippet for k in under_construction_kw):
                        status = 'design'
                    else:
                        status = 'unknown'
